 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import { FirehoseResource } from '@openshift-console/dynamic-plugin-sdk';
 4	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 5	import { RecentEventsBody } from '@openshift-console/dynamic-plugin-sdk-internal';
 6	import { EventKind } from '@openshift-console/dynamic-plugin-sdk-internal/lib/api/internal-types';
 7	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 8	import './activity-card.scss';
 9	
10	const eventsResource: FirehoseResource = {
11	  isList: true,
12	  kind: 'Event',
13	  prop: 'events',
14	};
15	
16	const ActivityCard: React.FC = () => {
17	  const { t } = useCustomTranslation();
18	  const [data, loaded, loadError] =
19	    useK8sWatchResource<EventKind[]>(eventsResource);
20	
21	  return (
22	    <Card>
23	      <CardHeader>
24	        <CardTitle>{t('Activity')}</CardTitle>
25	      </CardHeader>
26	      <CardBody className="odf-activityCard">
27	        <RecentEventsBody
28	          events={{
29	            data,
30	            loaded,
31	            loadError,
32	          }}
33	        />
34	      </CardBody>
35	    </Card>
36	  );
37	};
38	
39	export default ActivityCard;

